```class Solution {
public:
    int numberOfSubstrings(string s) {
        int res = 0, a = 0, b = 0, c = 0;
        for (int i = 0; i < s.size(); ++i) {
            if (s[i] == 'a') ++a;
            if (s[i] == 'b') ++b;
            if (s[i] == 'c') ++c;
            res += a * b * c;
        }
        return res;
    }
};
